def write_closeout_review(project_root: Path, *, review_path: Path) -> CloseoutReview:
    review = score_project(project_root)
    review_path.parent.mkdir(parents=True, exist_ok=True)
    lines = ["# PR11 Closeout Review", "", f"Score: {review.total_score}/100", "", "## Executed Criteria"]
    lines.extend(
        f"- [{'PASS' if item.passed else 'FAIL'}] {item.category} / {item.criterion_id}: {item.evidence}"
        for item in review.items
    )
    lines.extend(["", "## Gaps"])
    lines.extend(f"- {gap}" for gap in review.gaps) if review.gaps else lines.append("- None inside PR11 scope.")
    lines.extend(["", "## Outside PR11 Evidence"])
    lines.extend(f"- {item}" for item in review.outside_pr1)
    review_path.write_text("\n".join(lines) + "\n", encoding="utf-8")
    return review


def review_to_json(review: CloseoutReview) -> str:
